Create a program that has a function called counts that:

    counts all of the occurring characters in a string (UTF-8)
    if you have a string like "aba", the result should be {"a":2, "b":1}
    If the string is empty, return {}
import sys

def count_chars(y):
    char_counts = {}
    for x in y:
        if x in char_counts:
            char_counts[x] += 1
        else:
            char_counts[x] = 1
    return char_counts

if __name__ == "__main__":
    input_string = " ".join(sys.argv[1:]).strip()
    char_counts = count_chars(input_string)
    print(char_counts)

